"""HLD Key Technologies: API Gateway, Cassandra, DynamoDB — 20 deep MCQs each."""
from __future__ import annotations
from .lld_practice import quiz, Lesson

def api_gateway_lesson() -> Lesson:
    return Lesson(id="hld-api-gateway", number=119, title="API Gateway",
        focus=("routing","rate limiting","auth","protocol translation","service mesh","Kong/AWS"),
        overview="API Gateways are the front door of microservices. Know routing, auth, rate limiting, and protocol translation.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("gw-1","What is an API Gateway?","medium",("api-gateway",),("A single entry point for microservices handling routing, auth, rate limiting, and protocol translation","A DNS-based technique that distributes queries across multiple authoritative servers","A deployment strategy that gradually shifts traffic from the old version to the new one","A routing strategy that directs traffic based on geographic proximity of the client"),0,"API Gateways centralize cross-cutting concerns: auth, rate limiting, monitoring, protocol translation."),
        quiz("gw-2","What is the difference between an API Gateway and a load balancer?","hard",("api-gateway",),("LB distributes traffic; API Gateway adds intelligent routing, auth, rate limiting, request/response transformation","A coordination service that uses ephemeral nodes for automatic failure detection","A transaction isolation level that prevents phantom reads using predicate locking","A scheduling algorithm that assigns tasks to workers based on estimated completion time"),0,"L7 LB overlaps with Gateway but Gateway adds API-specific features like auth, throttling, and versioning."),
        quiz("gw-3","What is request routing in an API Gateway?","medium",("api-gateway",),("Directing requests to the correct microservice based on URL path, headers, or query parameters","A resilience pattern that isolates failures in one subsystem from propagating to others","A flow control mechanism that prevents the sender from overwhelming the receiver","A prefetching algorithm that predicts future access patterns from recent query history"),0,"/users → user-service, /orders → order-service. Path-based routing is most common."),
        quiz("gw-4","How does an API Gateway handle authentication?","medium",("api-gateway",),("Validates JWT/API keys at the gateway, so individual services don't need auth logic","Each service authenticates across multiple service instances","A replication strategy where writes go to any node and conflicts are resolved on read","A communication pattern where services exchange messages through a centralized broker"),0,"Gateway validates tokens once, adds user context to headers, forwards to services. Single auth point."),
        quiz("gw-5","What is rate limiting at the API Gateway level?","medium",("api-gateway",),("Enforcing request quotas per client/API key at the entry point before requests reach services","A transport layer optimization that reduces round-trip overhead using multiplexing","A partitioning algorithm that assigns data based on a hash of the geographic region","A membership protocol where nodes periodically exchange state with random cluster peers"),0,"Gateway rate limiting protects all downstream services. Uses token bucket or sliding window."),
        quiz("gw-6","What is protocol translation in an API Gateway?","hard",("api-gateway",),("Converting between protocols: HTTP REST externally ↔ gRPC/Thrift internally between microservices","A backup mechanism that captures incremental changes since the last full snapshot","A state synchronization approach that reconciles differences using Merkle tree comparison","A consistency model where reads from any replica are guaranteed to be monotonically fresh"),0,"Clients use REST/HTTP; internal services use gRPC for performance. Gateway bridges the protocols."),
        quiz("gw-7","What is the difference between Kong and AWS API Gateway?","hard",("api-gateway",),("Kong: self-hosted, Lua plugins, highly customizable. AWS: managed, Lambda integration, pay-per-request","A security protocol that authenticates both client and server during the handshake","A protocol that batches multiple requests into a single TCP segment for efficiency","A failure detection mechanism using heartbeat intervals and configurable timeout thresholds"),0,"Kong: open-source, runs anywhere. AWS API Gateway: managed, serverless-friendly, but AWS-locked."),
        quiz("gw-8","What is request aggregation (BFF pattern)?","hard",("api-gateway",),("Backend-for-Frontend: gateway combines responses from multiple services into a single client response","A monitoring approach that aggregates metrics from multiple sources into unified dashboards","A testing approach that injects controlled failures to verify system recovery behavior","A load balancing technique across multiple service instances"),0,"Mobile client needs data from 3 services. BFF gateway makes 3 internal calls, combines, returns one response."),
        quiz("gw-9","What is circuit breaking at the Gateway level?","hard",("api-gateway",),("Gateway stops forwarding to a failing service after a threshold, returning fallback responses","A load shedding strategy that drops low-priority requests when resource utilization is high","A technique where the server pre-fetches resources based on predicted client needs","A connection management approach that pins clients to specific backend instances"),0,"If user-service returns 500s, gateway trips circuit breaker → returns cached/default response → retries later."),
        quiz("gw-10","What is the service mesh vs API Gateway?","hard",("api-gateway",),("Gateway handles north-south traffic (client→service); service mesh handles east-west (service→service)","A replication technique that synchronously mirrors writes to a standby for zero data loss","A connection management approach that limits concurrent sessions to prevent overload","A mechanism that compresses HTTP headers to reduce bandwidth on repeated requests"),0,"Use both: API Gateway for external traffic, service mesh (Istio) for internal inter-service communication."),
        quiz("gw-11","What is request/response transformation?","medium",("api-gateway",),("Gateway modifies requests (add headers, change body format) or responses (filter fields, change status codes)","A warming strategy that pre-loads data based on access frequency from the previous day","A schema design pattern that embeds frequently accessed data to avoid join overhead","A partitioning strategy that splits data based on a hash of the composite primary key"),0,"Transform legacy service responses to match API contract without changing the service."),
        quiz("gw-12","What is API throttling vs rate limiting?","medium",("api-gateway",),("Rate limiting caps requests per time window; throttling queues excess requests and processes them later","A technique that partitions workload across worker pools based on resource requirements","A replication technique that mirrors hot cache entries across multiple nodes for availability","A sharding approach that distributes cached entries across nodes by consistent hashing"),0,"Rate limit: reject excess. Throttle: queue excess. Choose based on client expectations."),
        quiz("gw-13","How does an API Gateway handle versioning?","medium",("api-gateway",),("Routes /v1/* to old service and /v2/* to new service, enabling gradual migration","A pattern where incoming requests are buffered and processed in priority-ordered batches","A persistence mechanism that snapshots the cache state to disk for crash recovery","A serialization format that reduces cache entry size through schema-aware compression"),0,"Gateway-based versioning: route by path prefix, header (Accept-Version), or query param."),
        quiz("gw-14","What is canary deployment via API Gateway?","hard",("api-gateway",),("Route a small percentage of traffic to a new service version, gradually increasing if healthy","A monitoring tool that tracks hit rates, eviction counts, and memory usage per cache pool","A data pipeline stage that transforms and enriches events before writing to storage","A data structure that stores cache metadata compactly using probabilistic counting"),0,"Canary: 1% traffic → new version. Monitor errors/latency. Gradually increase to 100% or rollback."),
        quiz("gw-15","What is the fan-out pattern at the Gateway?","hard",("api-gateway",),("One client request triggers parallel calls to multiple services, results aggregated before responding","A congestion avoidance algorithm that dynamically adjusts the transmission window","An eviction algorithm that considers both recency and frequency when selecting victims","A clock synchronization technique that uses NTP with bounded drift for ordering events"),0,"Gateway fans out to user-service, product-service, recommendation-service in parallel, aggregates results."),
        quiz("gw-16","What are the security features of an API Gateway?","medium",("api-gateway",),("SSL termination, JWT validation, OAuth2 flows, IP whitelisting, CORS handling, and WAF integration","A consensus protocol that uses a rotating leader to distribute write coordination load","A query optimization strategy that rewrites subqueries into more efficient join patterns","A process that periodically reconciles state between systems to detect and fix drift"),0,"Centralized security: one place to enforce all security policies before traffic reaches services."),
        quiz("gw-17","What is the single point of failure risk with API Gateways?","hard",("api-gateway",),("If the gateway goes down, all services become unreachable — mitigate with redundancy and multi-zone deployment","A cache coherence protocol that broadcasts invalidation messages to all cache tiers","A monitoring tool that tracks query execution plans and identifies slow running queries","A storage engine optimization that pre-sorts data on disk for sequential access patterns"),0,"Deploy gateway in multiple AZs with health checks. Use DNS failover between gateway instances."),
        quiz("gw-18","What is gRPC-Web and how does the API Gateway help?","hard",("api-gateway",),("Browsers can't use gRPC natively; the gateway translates HTTP/1.1 to gRPC, enabling browser-to-gRPC communication","An index maintenance operation that rebuilds fragmented pages for better scan performance","A database driver protocol optimized for low-latency SQL connections","A front-end JavaScript framework that handles page routing natively"),0,"Gateway as gRPC-Web proxy: browser sends HTTP → gateway converts to gRPC → forwards to service."),
        quiz("gw-19","What is the difference between edge and internal API Gateways?","hard",("api-gateway",),("Edge: handles external client traffic (auth, rate limiting). Internal: handles service-to-service routing (lighter)","Internal gateways handle all client-side traffic while edge gateways route between sub-services","Edge gateways are much simpler to deploy because they do not support TLS termination","There is no difference; the terms are used interchangeably based on the cloud vendor"),0,"Edge gateway is security-heavy. Internal gateway/mesh is performance-focused with less overhead."),
        quiz("gw-20","What is API composition pattern?","hard",("api-gateway",),("Gateway calls multiple services and composes a single API response — replaces distributed JOINs","An in-memory cache routing policy that stores responses client-side","A database replication model configured across database primary keys","A load balancing technique using configurable thresholds"),0,"Instead of clients making 5 calls, gateway makes 5 internal calls and returns one composed response."),
    ))

def cassandra_lesson() -> Lesson:
    return Lesson(id="hld-cassandra", number=120, title="Cassandra",
        focus=("partition key","clustering columns","consistency levels","compaction","gossip","SSTable"),
        overview="Cassandra is designed for massive write throughput and linear scalability. Know its data model and internals.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("cass-1","What is Cassandra's data model based on?","hard",("cassandra",),("Partition key + clustering columns — queries MUST include the partition key","A graph network of nodes and edges representing database relations","Standard normalized relational tables connected via foreign key constraints","Hierarchical JSON documents stored in collections similar to MongoDB"),0,"Design around query patterns. Partition key determines data placement; clustering columns sort within."),
        quiz("cass-2","What is a partition key in Cassandra?","hard",("cassandra",),("The column(s) whose hash determines which node stores the data — defines data distribution","A database index that maps table rows to memory addresses based on primary keys","A sort key used to order rows chronologically within a database partition","A single primary key column that uniquely identifies a row in a table"),0,"Choosing a good partition key is the single most important Cassandra design decision."),
        quiz("cass-3","What are clustering columns?","hard",("cassandra",),("Columns that define sort order within a partition — enabling range queries within the partition","Columns that determine data distribution across cluster partition rings","Index fields used to accelerate lookups on non-partition columns","Foreign keys used to join tables together in distributed queries"),0,"Clustering columns: ORDER BY within a partition. E.g., PRIMARY KEY (user_id, created_at) sorts by time."),
        quiz("cass-4","What is Cassandra's consistency model?","hard",("cassandra",),("Tunable per query: ONE (fast, stale), QUORUM (balanced), ALL (slow, consistent)","Strictly strong consistency under all read and write configurations","Serializable transaction isolation, matching standard SQL databases","Eventual consistency only, with no options to tune read or write path behavior"),0,"Tunable consistency: choose per operation. QUORUM = majority of replicas respond."),
        quiz("cass-5","What is the gossip protocol in Cassandra?","hard",("cassandra",),("Peer-to-peer protocol where nodes periodically exchange cluster state (membership, health)","A query execution protocol used to coordinate cross-node joins","A data replication mechanism where nodes push updates to standby replicas","A consensus algorithm like Raft that elects a single master node"),0,"Gossip: no central coordinator. Nodes learn about each other through periodic state exchanges."),
        quiz("cass-6","What is an SSTable in Cassandra?","hard",("cassandra",),("Sorted String Table: an immutable on-disk file of key-value pairs, created when memtable flushes","A memory-mapped cache that holds frequently accessed database records","A standard SQL database table structure stored in row-oriented files","A sequential write-ahead log file used to recover from server crashes"),0,"Write path: memtable (memory) → flush → SSTable (disk). SSTables are immutable, merged by compaction."),
        quiz("cass-7","What is compaction in Cassandra?","hard",("cassandra",),("Merging multiple SSTables to remove tombstones, deduplicate, and improve read performance","A replication protocol step that copies files between regional nodes","A compression algorithm that reduces the size of SSTable files on disk","An automated backup utility that schedules daily database snapshots"),0,"Compaction strategies: SizeTiered (write-heavy), Leveled (read-heavy), TimeWindow (time-series)."),
        quiz("cass-8","What is a tombstone in Cassandra?","hard",("cassandra",),("A marker for deleted data; kept until compaction removes it after gc_grace_seconds","A status metadata field indicating that a physical server has failed","A marker placed in backup files to indicate snapshot boundaries","A specialized index entry used to speed up deletion query lookups"),0,"Tombstones propagate deletes across replicas. Too many tombstones slow reads — tune gc_grace_seconds."),
        quiz("cass-9","What is the write path in Cassandra?","hard",("cassandra",),("Commit log (WAL) → memtable (memory) → flush to SSTable (disk) when memtable is full","Writing directly to the SSTable file on disk without memory buffering","Writing to a cache layer which updates the database asynchronously","Writing straight to the main storage disk block using random access I/O"),0,"Commit log ensures durability. Memtable accumulates writes. SSTable flush is sequential I/O."),
        quiz("cass-10","What is the read path in Cassandra?","hard",("cassandra",),("Bloom filter → key cache → partition index → SSTable → merge results from multiple SSTables","Looking up keys from the memory cache and ignoring disk storage","Reading directly from the raw SSTable file without using bloom filters","Searching only the active memtable segment in memory for the key"),0,"Bloom filter: quickly check if an SSTable might contain the key. Avoids unnecessary disk reads."),
        quiz("cass-11","What is Cassandra's replication strategy?","hard",("cassandra",),("Each partition replicated to N nodes (replication_factor). SimpleStrategy or NetworkTopologyStrategy","Cassandra does not support replication, relying on hardware backups instead","Synchronous two-phase replication across all node clusters in the ring","A master-replica architecture where a single master node coordinates all writes"),0,"NetworkTopologyStrategy: specify replicas per datacenter. Data placed on nodes via consistent hashing."),
        quiz("cass-12","What is a materialized view in Cassandra?","hard",("cassandra",),("An automatically maintained copy of data with a different partition key for alternate query patterns","A manually copied backup table created by the system administrator","An in-memory cache layer that stores precomputed query outputs","A virtual query view that does not store any physical data copies"),0,"MVs let you query by different columns but have consistency overhead. Many teams prefer manual denormalization."),
        quiz("cass-13","Why doesn't Cassandra support JOINs?","hard",("cassandra",),("Data is distributed across nodes — JOINs would require cross-node coordination, defeating the purpose","A design limitation that will be resolved in future versions","Cassandra does support JOINs natively when using the clustering key query","JOINs are technically supported but disabled by default to save storage"),0,"Cassandra philosophy: denormalize and duplicate data. Design tables around query patterns, not normalized models."),
        quiz("cass-14","What is lightweight transaction (LWT) in Cassandra?","hard",("cassandra",),("IF NOT EXISTS / IF conditions using Paxos consensus — linearizable but much slower than normal writes","A database indexing scheme optimized for fast transactional reads","A standard two-phase commit transaction supported across all shards","A batch execution mode that group writes together without locks"),0,"LWTs provide linearizable consistency for critical operations (e.g., unique username check) at 4-10x latency cost."),
        quiz("cass-15","What is the repair process in Cassandra?","hard",("cassandra",),("Anti-entropy repair: compares Merkle trees across replicas, syncs any differences to ensure consistency","A snapshot restore process that rolls back corruption errors","A compaction strategy designed to merge small SSTable files","A hardware maintenance procedure for replacing failed server drives"),0,"Run nodetool repair regularly (within gc_grace_seconds) to prevent resurrected tombstones."),
        quiz("cass-16","What are secondary indexes in Cassandra and when to avoid them?","hard",("cassandra",),("Indexes on non-partition columns — avoid for high-cardinality columns as they query all nodes","Creating indexes on every single column to speed up arbitrary searches","Distributed indexing structures that replace the need for partition keys","A replication configuration that should always be enabled for query paths"),0,"Secondary indexes: full cluster scan for high-cardinality. Use materialized views or denormalized tables instead."),
        quiz("cass-17","What is Cassandra's token ring?","hard",("cassandra",),("Each node owns a range of tokens on a consistent hash ring; data is placed based on partition key hash","A physical network routing layout connecting servers in a circle","A cryptographic token used to authorize client API requests","A user session tracking system that manages client connection lifetimes"),0,"Token range: Murmur3 hash of partition key determines which node(s) store the data."),
        quiz("cass-18","What is hinted handoff in Cassandra?","hard",("cassandra",),("When a replica is temporarily down, another node stores the write as a hint and delivers it when the node recovers","A TCP network handshake optimization that reduces packet latency","A compaction technique that combines small SSTables sequentially","A backup process that copies deleted records to remote storage"),0,"Hinted handoff: temporary store-and-forward. Hints expire after a configurable period."),
        quiz("cass-19","What is the difference between Cassandra and ScyllaDB?","hard",("cassandra",),("ScyllaDB is Cassandra-compatible but written in C++ (vs Java), offering lower latency and better hardware utilization","ScyllaDB is a slower, archive-only version of Cassandra","They are identical databases; the name differs based on the hosting cloud","They use completely different data models and API query languages"),0,"ScyllaDB: shard-per-core architecture, no JVM GC pauses. Drop-in Cassandra replacement with better perf."),
        quiz("cass-20","How do you model a time-series workload in Cassandra?","hard",("cassandra",),("Partition by entity + time bucket (e.g., sensor_id + day), cluster by timestamp — prevents unbounded partitions","Cassandra does not support time-series workloads due to indexing limits","Storing all time-series records in a single monolithic table without keys","Creating a separate partition for every individual sensor data reading"),0,"Time bucketing: partition by (sensor_id, date). Limits partition size. Query by sensor + date range."),
    ))

def dynamodb_lesson() -> Lesson:
    return Lesson(id="hld-dynamodb", number=121, title="DynamoDB",
        focus=("partition key","sort key","GSI/LSI","capacity modes","streams","transactions"),
        overview="DynamoDB is AWS's managed NoSQL. Know its data model, capacity modes, and advanced features.",
        patterns=(), badge="HLD Tech", tasks=(
        quiz("ddb-1","What is DynamoDB's primary key model?","medium",("dynamodb",),("Partition key (hash) alone, or partition key + sort key (range) for composite keys","A single UUID column generated automatically by the database engine","An auto-incrementing integer key similar to MySQL primary keys","A relational schema mapping where primary keys are connected via foreign keys"),0,"Partition key: data placement. Sort key: range queries within a partition. Simple or composite."),
        quiz("ddb-2","What is the difference between GSI and LSI?","hard",("dynamodb",),("GSI: different partition key, stored separately, eventually consistent. LSI: same partition key, different sort key, strongly consistent","LSI is a global secondary index; GSI is a local secondary index","GSI is a physical index; LSI is a virtual index mapped in memory","There is no difference; they are different names for the same index type"),0,"GSI: can query by any attribute. LSI: must share the table's partition key. LSI created at table creation only."),
        quiz("ddb-3","What is on-demand vs provisioned capacity?","medium",("dynamodb",),("On-demand auto-scales per request; provisioned requires pre-set RCU/WCU, cheaper for predictable workloads","On-demand capacity is always cheaper than provisioned capacity for all workloads","There is no difference; they both scale automatically to handle peaks","Provisioned capacity is a deprecated legacy feature not recommended for new tables"),0,"On-demand: 6-7x more expensive per request but zero capacity planning. Provisioned with auto-scaling is common."),
        quiz("ddb-4","What is a DynamoDB Stream?","hard",("dynamodb",),("An ordered log of item-level changes (INSERT, MODIFY, DELETE) that can trigger Lambda functions","A cached query result stream stored in the Accelerator layer","A Kafka topic integrated natively inside the AWS database engine","A backup recovery feature that records transaction logs to S3"),0,"Streams enable CDC: react to data changes, build materialized views, replicate to other systems."),
        quiz("ddb-5","What is a hot partition in DynamoDB?","hard",("dynamodb",),("A partition receiving traffic exceeding its throughput limit due to uneven key distribution","A physical server cooling failure inside the AWS datacenter","A cache eviction collision in the Accelerator (DAX) layer","A network routing congestion bottleneck at the VPC gateway"),0,"DynamoDB limits throughput per partition (~3000 RCU, 1000 WCU). Hot partitions get throttled."),
        quiz("ddb-6","How does DynamoDB handle transactions?","hard",("dynamodb",),("TransactWriteItems / TransactGetItems: atomic operations across up to 100 items in multiple tables","DynamoDB only supports single-item atomic operations, not multi-item transactions","Using standard SQL COMMIT and ROLLBACK commands across tables","DynamoDB does not support transactions; consistency must be managed in code"),0,"DynamoDB transactions: ACID across items. 2x cost of normal operations. Max 100 items per transaction."),
        quiz("ddb-7","What is the single-table design pattern?","hard",("dynamodb",),("Store all entity types in one table using composite keys (PK/SK) and overloaded GSIs for multiple access patterns","A relational database pattern that consolidates tables to speed up SQL joins","A standard NoSQL design where each application entity has its own table","A backup optimization strategy that saves all tables into a single S3 file"),0,"Single-table: PK=USER#123, SK=PROFILE or SK=ORDER#456. GSI1PK=ORDER#456 for order lookups."),
        quiz("ddb-8","What is a DynamoDB RCU and WCU?","medium",("dynamodb",),("Read Capacity Unit: one strongly consistent 4KB read/sec. Write Capacity Unit: one 1KB write/sec","Cache memory units allocated to the table's index buffers","VPC network bandwidth quotas allocated to the database endpoint","Virtual CPU cores assigned to process the table's write queries"),0,"RCU: 4KB strongly consistent or 8KB eventually consistent per unit. WCU: 1KB per unit per second."),
        quiz("ddb-9","What is adaptive capacity in DynamoDB?","hard",("dynamodb",),("DynamoDB automatically redistributes unused throughput from cold partitions to hot ones","A database replication configuration that scales across AWS regions","A manual capacity scaling tool operated via the AWS CLI","A memory caching algorithm that adjusts cache sizes dynamically"),0,"Adaptive capacity partially mitigates hot partitions by borrowing unused throughput. Not a complete solution."),
        quiz("ddb-10","What is DynamoDB Accelerator (DAX)?","hard",("dynamodb",),("A fully managed, in-memory cache for DynamoDB providing microsecond read latency","An automatic CPU upgrade options for high-throughput DynamoDB instances","A global CDN caching service optimized for static web files","A continuous backup utility that copies table states to S3"),0,"DAX: drop-in caching layer. Same API as DynamoDB. Microsecond reads for cached data."),
        quiz("ddb-11","What is the write sharding pattern in DynamoDB?","hard",("dynamodb",),("Add a random suffix to partition key to distribute writes (e.g., counter#1, counter#2, ..., counter#N)","Splitting tables into multiple smaller tables to avoid size limit bottlenecks","A read path optimization that caches index lookups client-side","A backup recovery strategy that partitions snapshot files"),0,"Write sharding spreads hot keys across partitions. Read requires scatter-gather across N suffixed keys."),
        quiz("ddb-12","What is the difference between strongly and eventually consistent reads?","medium",("dynamodb",),("Strongly consistent reads from the leader partition; eventually consistent reads may come from any replica","They are identical in behavior, differing only in network bandwidth cost","Eventually consistent reads are always guaranteed to return the latest write","Strongly consistent reads are eventually updated by a background process"),0,"Eventually consistent: 2x throughput, might be stale. Strongly consistent: 1x throughput, always latest."),
        quiz("ddb-13","What is point-in-time recovery (PITR) in DynamoDB?","medium",("dynamodb",),("Continuous backups enabling restoration to any point within the last 35 days","A manual backup scheduling option managed via the AWS console","A database replication feature that mirrors tables to other regions","A cache recovery strategy that restores the Accelerator layer on boot"),0,"PITR: automatic continuous backups. Restore to any second in the last 35 days. No performance impact."),
        quiz("ddb-14","How does DynamoDB handle global tables?","hard",("dynamodb",),("Multi-region, multi-active replication with eventual consistency and last-writer-wins conflict resolution","By restricting table writes to a single primary regional endpoint","By utilizing read-only replicas located in remote geographic zones","By requiring manual setup of data synchronization using custom Lambda scripts"),0,"Global tables: write anywhere, replicate everywhere. Conflicts resolved by last-writer-wins (timestamp)."),
        quiz("ddb-15","What are condition expressions in DynamoDB?","hard",("dynamodb",),("Conditional writes: only proceed if a condition is met (e.g., attribute_not_exists for unique inserts)","SQL WHERE statements translated to filter results at the client level","A search filter that excludes items after the query has completed","A secondary index lookup rule configured during table setup"),0,"Condition expressions enable optimistic locking: update only if version matches expected value."),
        quiz("ddb-16","What is the batch operations limit in DynamoDB?","medium",("dynamodb",),("BatchWriteItem: max 25 items, 16MB. BatchGetItem: max 100 items, 16MB","Exactly 100 items or 1 MB total payload size","Exactly 1,000 items or 10 MB total payload size","There is no limit on item count; limits are based only on network bandwidth"),0,"Batch operations are not transactional (partial failures possible). Use transactions for atomicity."),
        quiz("ddb-17","What is the difference between Scan and Query in DynamoDB?","medium",("dynamodb",),("Query uses the partition key (efficient). Scan reads every item in the table (expensive)","Query scans all table rows in search of matching non-key fields","They are identical operations, named differently for compatibility","Scan is a faster lookup mode that uses cache indexes rather than disks"),0,"Always prefer Query. Scan reads entire table, consuming throughput proportional to table size."),
        quiz("ddb-18","What is DynamoDB's pricing model?","medium",("dynamodb",),("Pay per RCU/WCU (provisioned) or per request (on-demand), plus storage ($0.25/GB/month) and data transfer","A flat price per table regardless of query volume or data size","A fixed monthly fee determined by the instance type chosen","A free-tier-only pricing model supported by advertising revenue"),0,"Cost optimization: use provisioned with auto-scaling for predictable workloads, on-demand for spiky."),
        quiz("ddb-19","What is a sparse GSI in DynamoDB?","hard",("dynamodb",),("A GSI where not all items have the indexed attribute — only items with that attribute appear in the GSI","A compressed index format that saves storage by stripping attributes","A full copy of the main table stored in a separate database partition","A standard index where results are filtered client-side"),0,"Sparse GSI: index only items where attribute exists. Reduces GSI size and cost. Great for status-based queries."),
        quiz("ddb-20","How do you handle large items (>400KB) in DynamoDB?","hard",("dynamodb",),("Store the large data in S3 and save the S3 reference URL in DynamoDB","Splitting the object fields across multiple database rows","Upgrading the table configuration to increase the item size limit","It is not possible to store items larger than 400KB in any AWS storage"),0,"DynamoDB max item: 400KB. For larger data: S3 for blob, DynamoDB for metadata and S3 pointer."),
    ))
